class Experiment:
    """Run experiments across tasks × configs × repetitions.
    
    The simplest usage:
        exp = Experiment(name="quick_test", run=my_function)
        results = exp.run()
    
    Full usage:
        exp = Experiment(
            name="grid_search",
            run=train_model,
            tasks=[task1, task2],
            configs=[{"lr": 0.1}, {"lr": 0.01}],
            repetitions=3,
            evaluators=[accuracy_eval, loss_eval],
            description="Comparing learning rates"
        )
        results = exp.run()
    
    Args:
        name: Required. Experiment name for saving and display.
        run: Required. Function to run for each (task, config) pair.
        tasks: Optional list of tasks (anything with a .name attribute).
        configs: Optional list of config dicts.
        repetitions: Number of times to repeat each (task, config) pair.
        evaluators: Optional list of Evaluator objects.
        description: Optional human-readable description.
        save: Whether to save results (default True).
        save_path: Custom save path (auto-generated if not provided).
    """
    
    def __init__(
        self,
        name: str,
        run,
        tasks: list | None = None,
        configs: list[dict] | None = None,
        repetitions: int = 1,
        evaluators: list | None = None,
        description: str | None = None,
        save: bool = True,
        save_path: str | None = None,
    ):
        self.name = name
        self.run_func = run
        self.tasks = tasks
        self.configs = configs
        self.repetitions = repetitions
        self.evaluators = evaluators or []
        self.description = description
        self.save = save
        self.save_path = save_path or _generate_save_path(name) if save else None
        
        # Validate configs upfront
        if self.configs:
            _check_duplicate_config_names(self.configs)
    
    def run(self) -> ExperimentResults:
        """Execute the experiment and return results."""
        results: list[TaskResult] = []
        
        # Determine what we're iterating over
        tasks = self.tasks or [None]
        configs = self.configs or [{}]
        has_tasks = self.tasks is not None
        has_configs = self.configs is not None
        
        # Detect calling convention
        convention = _detect_calling_convention(self.run_func, has_tasks, has_configs)
        
        # Main loop: tasks × configs × repetitions
        total_runs = len(tasks) * len(configs) * self.repetitions
        run_count = 0
        
        for task in tasks:
            task_name = task.name if task else "default"
            
            for config in configs:
                cfg_name = config_name(config)
                
                for rep in range(self.repetitions):
                    run_count += 1
                    eval_logger.info(f"Run {run_count}/{total_runs}: {task_name} x {cfg_name} (rep {rep+1})")
                    
                    result = self._run_single(task, config, task_name, cfg_name, convention)
                    results.append(result)
                    
                    # Save intermediate results
                    if self.save and self.save_path:
                        exp_results = ExperimentResults(
                            results=results,
                            experiment_name=self.name,
                            description=self.description,
                        )
                        exp_results.save(self.save_path)
        
        final_results = ExperimentResults(
            results=results,
            experiment_name=self.name,
            description=self.description,
            save_path=self.save_path,
        )
        
        return final_results
    
    def _run_single(self, task, config: dict, task_name: str, cfg_name: str, convention: str) -> TaskResult:
        """Run a single (task, config) combination."""
        start_time = time.time()
        output = None
        error = None
        
        try:
            # Call based on convention
            if convention == 'none':
                output = self.run_func()
            elif convention == 'task':
                output = self.run_func(task)
            elif convention == 'config':
                # Filter out 'name' key from config before passing
                run_config = {k: v for k, v in config.items() if k != 'name'}
                output = self.run_func(**run_config)
            elif convention == 'both':
                run_config = {k: v for k, v in config.items() if k != 'name'}
                output = self.run_func(task, **run_config)
        except Exception as e:
            error = e
            warnings.warn(f"Run failed: {task_name} x {cfg_name}: {e}")
        
        duration = time.time() - start_time
        
        # Run evaluators
        evaluations = []
        if output is not None:
            for evaluator in self.evaluators:
                try:
                    evals = evaluator.evaluate(output, task=task, config=config)
                    evaluations.extend(evals)
                except Exception as e:
                    warnings.warn(f"Evaluator '{evaluator.name}' failed: {e}")
            
            # Check for duplicate evaluation names
            if evaluations:
                _check_duplicate_evaluation_names(evaluations)
        
        return TaskResult(
            output=output,
            duration=duration,
            task_name=task_name,
            config_name=cfg_name,
            evaluations=evaluations,
            error=error,
        )


# %% ../nbs/01_evaluation.ipynb 27
def run_experiment(
    name: str,
    run,
    tasks: list | None = None,
    configs: list[dict] | None = None,
    repetitions: int = 1,
    evaluators: list | None = None,
    description: str | None = None,
    save: bool = True,
    save_path: str | None = None,
) -> ExperimentResults:
    """Convenience function to run an experiment.
    
    This is a thin wrapper around Experiment for quick one-off experiments.
    
    Examples:
        # Simplest case
        results = run_experiment(name="test", run=my_func)
        
        # With configs
        results = run_experiment(
            name="compare_lr",
            run=train,
            configs=[{"lr": 0.1}, {"lr": 0.01}]
        )
    
    See Experiment class for full documentation.
    """
    exp = Experiment(
        name=name,
        run=run,
        tasks=tasks,
        configs=configs,
        repetitions=repetitions,
        evaluators=evaluators,
        description=description,
        save=save,
        save_path=save_path,
    )
    return exp.run()


# %% ../nbs/01_evaluation.ipynb 36
def to_dataframe(results: ExperimentResults):
    """Convert ExperimentResults to a pandas DataFrame.
    
    Requires pandas to be installed.
    """
    import pandas as pd
    
    rows = []
    for r in results:
        row = {
            "task_name": r.task_name,
            "config_name": r.config_name,
            "duration": r.duration,
            "error": str(r.error) if r.error else None,
        }
        # Add all evaluations as columns
        for e in r.evaluations:
            row[e.name] = e.value
        rows.append(row)
    
    return pd.DataFrame(rows)


# %% ../nbs/01_evaluation.ipynb 38
def plot_success_rates(results: ExperimentResults, by: str = "config", figsize: tuple = (10, 6)):
    """Plot success rates as a bar chart.
    
    Args:
        results: ExperimentResults to plot
        by: Group by "config" or "task"
        figsize: Figure size tuple (width, height)
    
    Returns:
        matplotlib Figure object
    """
    import matplotlib.pyplot as plt
    
    if by == "config":
        names = sorted(results.config_names)
        rates = [results.by_config(n).success_rate or 0 for n in names]
        xlabel = "Config"
    else:
        names = sorted(results.task_names)
        rates = [results.by_task(n).success_rate or 0 for n in names]
        xlabel = "Task"
    
    fig, ax = plt.subplots(figsize=figsize)
    bars = ax.bar(range(len(names)), rates, color='steelblue', edgecolor='black')
    
    ax.set_xticks(range(len(names)))
    ax.set_xticklabels(names, rotation=45, ha='right')
    ax.set_ylabel("Success Rate (%)")
    ax.set_xlabel(xlabel)
    ax.set_ylim(0, 100)
    ax.set_title(f"Success Rate by {xlabel}")
    
    # Add value labels on bars
    for bar, rate in zip(bars, rates):
        ax.text(bar.get_x() + bar.get_width()/2, bar.get_height() + 2,
               f'{rate:.1f}%', ha='center', va='bottom', fontsize=9)
    
    plt.tight_layout()
    return fig


# %% ../nbs/01_evaluation.ipynb 39
def plot_heatmap(results: ExperimentResults, metric: str = "success", figsize: tuple = None):
    """Plot a heatmap of task x config results.
    
    Args:
        results: ExperimentResults to plot
        metric: Name of evaluation to plot (default "success")
        figsize: Figure size, auto-calculated if None
    
    Returns:
        matplotlib Figure object
    """
    import matplotlib.pyplot as plt
    import numpy as np
    
    tasks = sorted(results.task_names)
    configs = sorted(results.config_names)
    
    if len(tasks) <= 1 or len(configs) <= 1:
        raise ValueError("Heatmap requires at least 2 tasks and 2 configs")
    
    # Build matrix
    matrix = np.zeros((len(tasks), len(configs)))
    for i, task in enumerate(tasks):
        for j, config in enumerate(configs):
            subset = results.by_task(task).by_config(config)
            if metric == "success":
                val = subset.success_rate or 0
            else:
                vals = subset.get_evaluation_values(metric)
                val = np.mean(vals) if vals else 0
            matrix[i, j] = val
    
    # Auto figure size
    if figsize is None:
        figsize = (max(6, len(configs) * 1.5), max(4, len(tasks) * 0.8))
    
    fig, ax = plt.subplots(figsize=figsize)
    
    if metric == "success":
        im = ax.imshow(matrix, cmap='RdYlGn', vmin=0, vmax=100)
    else:
        im = ax.imshow(matrix, cmap='viridis')
    
    ax.set_xticks(range(len(configs)))
    ax.set_yticks(range(len(tasks)))
    ax.set_xticklabels(configs, rotation=45, ha='right')
    ax.set_yticklabels(tasks)
    ax.set_xlabel("Config")
    ax.set_ylabel("Task")
    
    # Add text annotations
    for i in range(len(tasks)):
        for j in range(len(configs)):
            val = matrix[i, j]
            text = f'{val:.1f}%' if metric == "success" else f'{val:.2f}'
            ax.text(j, i, text, ha='center', va='center', fontsize=9)
    
    plt.colorbar(im, label=metric.capitalize())
    ax.set_title(f"{metric.capitalize()} by Task × Config")
    plt.tight_layout()
    return fig


