def to_csv(results: ExperimentResults, path: str):
    """Export ExperimentResults to a CSV file.
    
    Args:
        results: ExperimentResults to export
        path: Path to save the CSV file
    """
    df = to_dataframe(results)
    df.to_csv(path, index=False)
    return path

